/**
 * @fileoverview Card component — modular entry point.
 * @module module/Card
 */

import { default as razyui } from '../../index.js';
import { CardDef as DEF } from '../Card.def.js';
import { DEFAULTS, CLS } from './constants.js';
import { setupDOM, cleanupDOM } from './view.js';

const Card = class {
    #root   = null;
    #destroyed = false;
    #config = {};

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Card: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        setupDOM(root, this.#config);
    }

    setLoading(loading) {
        if (loading) this.#root.addClass(CLS.LOADING);
        else this.#root.removeClass(CLS.LOADING);
        this.#root[0].setAttribute('aria-busy', String(!!loading));
    }

    getControl() {
        const self = this;
        return {
            get loading()  { return self.#root.hasClass?.(CLS.LOADING) ?? false; },
            set loading(v) { self.setLoading(v); },
            get title()    { const t = self.#root[0]?.querySelector?.('.card-title'); return t ? t.textContent : ''; },
            set title(v)   { const t = self.#root[0]?.querySelector?.('.card-title'); if (t) t.textContent = v ?? ''; },
            get bordered() { return self.#config.bordered; },
            set bordered(v){ self.#config.bordered = !!v; },
            setLoading: (v) => self.setLoading(v),
            destroy:    () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        cleanupDOM(this.#root);
    }
};

export default Card;
