/**
 * @fileoverview Card constants.
 * @module module/Card/constants
 */

import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:   'card',
    HEADER: 'card-header',
    BODY:   'card-body',
    FOOTER: 'card-footer',
    TITLE:  'card-title',
    LOADING: 'is-loading',
});

export const DEFAULTS = Object.freeze({
    title: null,
    loading: false,
    bordered: true,
    hoverable: false,
});

export const PART = defineParts('Card', {
    ROOT:   { class: 'card-container', aliases: ['root', 'container'] },
    HEADER: { class: 'card-header', aliases: ['header'] },
    BODY:   { class: 'card-body', aliases: ['body'] },
    FOOTER: { class: 'card-footer', aliases: ['footer'] },
    TITLE:  { class: 'card-title', aliases: ['title'], tag: 'span' },
});

PART.ROOT.jit   = 'flex flex-col bg-[var(--cd-bg)] rounded-[var(--cd-radius)] [border:1px_solid_var(--cd-border)] shadow-[var(--cd-shadow)] overflow-hidden [font-family:var(--cd-font-stack)] {is-loading}:opacity-60 {is-loading}:pointer-events-none';
PART.HEADER.jit = 'flex items-center px-[var(--cd-px)] py-[var(--cd-header-py)] [border-bottom:1px_solid_var(--cd-border)]';
PART.BODY.jit   = 'flex-1 px-[var(--cd-px)] py-[var(--cd-py)]';
PART.FOOTER.jit = 'flex items-center px-[var(--cd-px)] py-[var(--cd-footer-py)] [border-top:1px_solid_var(--cd-border)]';
PART.TITLE.jit  = 'text-[var(--cd-title-size)] font-semibold fg-[var(--cd-title-color)]';
