/**
 * @fileoverview Card view — DOM setup.
 * @module module/Card/view
 */

import { CLS, PART } from './constants.js';

export function setupDOM(root, config) {
    const { title, bordered, hoverable } = config;

    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    if (!bordered) root.css('border', 'none');
    if (hoverable) root.css('transition', 'box-shadow .2s, transform .2s');

    // Header (only if title provided)
    let headerEl = null;
    if (title) {
        const $header = PART.HEADER.create();
        const $title = PART.TITLE.create().text(title);
        $header.append($title);
        root.append($header);
        headerEl = $header;
    }

    // Body (move existing children into body)
    const $body = PART.BODY.create();

    // Move existing content to body
    const existingNodes = [];
    for (const child of root[0].childNodes) {
        if (child !== headerEl?.[0]) existingNodes.push(child);
    }
    for (const node of existingNodes) {
        $body.append(node);
    }

    root.append($body);

    return { headerEl, bodyEl: $body };
}

export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT);
}
